'use client';

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/lib/supabase';
import { useAuth } from '@/lib/auth-context';
import { useApp } from '@/lib/context';
import AgentCommissionsPanel from '@/components/negocio/AgentCommissionsPanel';
import AgentReferralsPanel from '@/components/negocio/AgentReferralsPanel';

export default function NegocioClient({ initialReservations = [], initialContacts = [], initialCommissions = [], initialTiers = [], initialReferrals = [], initialEvents = [], initialAttendance = [] }) {
  const { user, profile } = useAuth();
  const { t } = useApp();

  const [reservations, setReservations] = useState(initialReservations);
  const [contacts, setContacts] = useState(initialContacts);
  const [loading, setLoading] = useState(false);
  const [serverDataLoaded] = useState(() => true); // Server component already fetched data

  // Modals/Drawers
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [selectedRes, setSelectedRes] = useState(null);

  // Form state
  const [formData, setFormData] = useState({
    property_address: '',
    buyer_name: '',
    buyer_contact_id: '',
    seller_name: '',
    seller_contact_id: '',
    registry_numbers: '',
    plan_numbers: '',
    type: 'LOI',
    side: 'listing',
    reservation_amount: '',
    sale_price: '',
    commission_pct: 5,
    expected_sign_date: '',
    close_deadline: '',
    earnest_money_deadline: '',
    earnest_money_non_refundable_date: '',
    earnest_money_non_refundable_date: '',
    buyer_agent_name: '',
    buyer_agent_office: '',
    seller_agent_name: '',
    seller_agent_office: '',
    buyer_notary_id: '',
    buyer_notary_name: '',
    seller_notary_id: '',
    seller_notary_name: '',
    negotiation_details: '',
    drive_folder_url: ''
  });

  const [aiLoading, setAiLoading] = useState(false);
  const [isCreatingFolder, setIsCreatingFolder] = useState(false);
  const [activeTab, setActiveTab] = useState('reservas');

  // Only re-fetch if the server component didn't provide any data
  // (e.g. user navigated client-side without a full page load)
  // The server component always pre-fetches, so we skip redundant client-side fetches
  // that may fail due to auth/table issues in production
  const fetchContacts = useCallback(async () => {
    try {
      const { data } = await supabase.from('contacts').select('id, first_name, last_name, type').order('first_name');
      if (data) setContacts(data);
    } catch (err) {
      console.error('Error fetching contacts:', err);
    }
  }, []);

  const fetchReservations = useCallback(async () => {
    if (!profile?.id) return;
    try {
      setLoading(true);
      const { data, error } = await supabase
        .from('office_reservations')
        .select(`
          *,
          due_diligence_items (*)
        `)
        .eq('profile_id', profile.id)
        .order('created_at', { ascending: false });

      if (error) throw error;
      setReservations(data || []);
    } catch (err) {
      console.error('Error fetching reservations:', err);
    } finally {
      setLoading(false);
    }
  }, [profile?.id]);

  useEffect(() => {
    // Don't re-fetch if data was already loaded server-side
    if (serverDataLoaded) return;
    if (profile?.id) {
    // eslint-disable-next-line react-hooks/set-state-in-effect
      fetchReservations();
      fetchContacts();
    }
  }, [profile?.id, serverDataLoaded, fetchReservations, fetchContacts]);

  async function handleCreateDriveFolder() {
    if (!formData.property_address) {
      alert(t('neg_drive_alert_missing'));
      return;
    }
    const agentName = profile?.full_name || user?.user_metadata?.full_name || user?.user_metadata?.name || user?.email?.split('@')[0] || 'Agente';

    try {
      setIsCreatingFolder(true);
      const res = await fetch('/api/drive/create-folder', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          agentName: agentName,
          propertyName: `[${formData.type || 'LOI'}] ${formData.property_address}`
        })
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error || t('neg_drive_error'));

      setFormData(prev => ({ ...prev, drive_folder_url: data.folderUrl }));
      alert(`${t('neg_drive_success')} ${data.agentFolder}`);
    } catch (err) {
      console.error(err);
      alert(err.message);
    } finally {
      setIsCreatingFolder(false);
    }
  }



  // Calculate Pipeline Metrics
  const activeReservations = reservations.filter(r => r.status === 'pending' || r.status === 'signed');
  const pipelineValue = activeReservations.reduce((acc, r) => acc + (Number(r.sale_price) || 0), 0);
  const expectedCommission = activeReservations.reduce((acc, r) => {
    const comPct = Number(r.commission_pct) || 0;
    const price = Number(r.sale_price) || 0;
    let agentCom = r.agent_commission_amount;
    if (!agentCom) {
      // rough estimate if not set explicitly
      agentCom = (price * (comPct/100)) * 0.5; // assuming ~50% split for estimation
    }
    return acc + Number(agentCom);
  }, 0);

  // Calculate Attendance Percentage
  const attendanceRate = (() => {
    let totalCounted = 0;
    let totalPresent = 0;
    initialAttendance.forEach(att => {
      if (att.status === 'no_obligatoria') return;
      totalCounted++;
      if (att.status === 'presente') totalPresent++;
    });
    return totalCounted === 0 ? 100 : Math.round((totalPresent / totalCounted) * 100);
  })();

  async function handleSaveReservation(e) {
    e.preventDefault();
    try {
      const isEditing = !!formData.id;

      const safeNumber = (val) => {
        if (!val) return 0;
        const num = Number(val.toString().replace(/[^0-9.-]+/g,""));
        return isNaN(num) ? 0 : num;
      };

      const safeDate = (val) => {
        if (!val || val.trim() === '') return null;
        // Check if it's a valid date
        const d = new Date(val);
        return isNaN(d.getTime()) ? null : val;
      };

      const price = safeNumber(formData.sale_price);
      const commission = safeNumber(formData.commission_pct);

      let finalBuyerNotaryId = formData.buyer_notary_id;
      if (!finalBuyerNotaryId && formData.buyer_notary_name) {
        const { data: n1 } = await supabase.from('contacts').insert({ first_name: formData.buyer_notary_name, type: 'Notary', user_id: user.id }).select().single();
        if (n1) finalBuyerNotaryId = n1.id;
      }

      let finalSellerNotaryId = formData.seller_notary_id;
      if (!finalSellerNotaryId && formData.seller_notary_name) {
        const { data: n2 } = await supabase.from('contacts').insert({ first_name: formData.seller_notary_name, type: 'Notary', user_id: user.id }).select().single();
        if (n2) finalSellerNotaryId = n2.id;
      }

      const payload = {
        profile_id: profile.id,
        property_address: formData.property_address,
        buyer_name: formData.buyer_name,
        buyer_contact_id: formData.buyer_contact_id || null,
        seller_name: formData.seller_name,
        seller_contact_id: formData.seller_contact_id || null,
        registry_numbers: formData.registry_numbers,
        plan_numbers: formData.plan_numbers,
        type: formData.type,
        side: formData.side,
        reservation_amount: safeNumber(formData.reservation_amount),
        sale_price: price,
        commission_pct: commission,
        expected_sign_date: safeDate(formData.expected_sign_date),
        close_deadline: safeDate(formData.close_deadline),
        earnest_money_deadline: safeDate(formData.earnest_money_deadline),
        earnest_money_non_refundable_date: safeDate(formData.earnest_money_non_refundable_date),
        buyer_agent_name: formData.buyer_agent_name,
        buyer_agent_office: formData.buyer_agent_office,
        seller_agent_name: formData.seller_agent_name,
        seller_agent_office: formData.seller_agent_office,
        buyer_notary_id: finalBuyerNotaryId || null,
        seller_notary_id: finalSellerNotaryId || null,
        negotiation_details: formData.negotiation_details,
        drive_folder_url: formData.drive_folder_url,
        agent_commission_amount: (price * (commission/100)) * 0.5
      };

      if (isEditing) {
        const { error } = await supabase
          .from('office_reservations')
          .update(payload)
          .eq('id', formData.id);
        if (error) throw error;
      } else {
        const { error } = await supabase
          .from('office_reservations')
          .insert([payload]);
        if (error) throw error;
      }

      if (formData.buyer_contact_id && finalBuyerNotaryId) {
        await supabase.from('contact_relations').upsert({ contact_id: formData.buyer_contact_id, related_contact_id: finalBuyerNotaryId, relation_type: 'Notary' }, { onConflict: 'contact_id,related_contact_id' });
      }
      if (formData.seller_contact_id && finalSellerNotaryId) {
        await supabase.from('contact_relations').upsert({ contact_id: formData.seller_contact_id, related_contact_id: finalSellerNotaryId, relation_type: 'Notary' }, { onConflict: 'contact_id,related_contact_id' });
      }

      setIsAddModalOpen(false);
      fetchReservations();
    } catch (err) {
      console.error('Save error:', err);
      alert(t('neg_save_error') + err.message);
    }
  }

  async function requestBrokerHelp(resId) {
    const note = prompt(t('neg_broker_help_note'));
    if (note === null) return;

    try {
      const { error } = await supabase
        .from('office_reservations')
        .update({
          broker_help_requested: true,
          broker_help_note: note,
          broker_help_date: new Date().toISOString()
        })
        .eq('id', resId);

      if (error) throw error;
      alert(t('neg_broker_help_sent'));
      fetchReservations();
      if (selectedRes && selectedRes.id === resId) {
        setSelectedRes(prev => ({...prev, broker_help_requested: true}));
      }
    } catch (err) {
      console.error(err);
    }
  }

  async function handleFileUpload(e) {
    const file = e.target.files?.[0];
    if (!file) return;

    setAiLoading(true);
    try {
      const data = new FormData();
      data.append('file', file);

      const res = await fetch('/api/olympia/contract-extract', {
        method: 'POST',
        body: data,
      });

      const extracted = await res.json();
      if (!res.ok) throw new Error(extracted.error || t('neg_ai_extract_error'));

      // Merge extracted data into formData
      setFormData(prev => ({
        ...prev,
        type: extracted.type || prev.type,
        property_address: extracted.property_address || prev.property_address,
        buyer_name: extracted.buyer_name || prev.buyer_name,
        seller_name: extracted.seller_name || prev.seller_name,
        registry_numbers: extracted.registry_numbers || prev.registry_numbers,
        plan_numbers: extracted.plan_numbers || prev.plan_numbers,
        side: extracted.side || prev.side,
        sale_price: extracted.sale_price || prev.sale_price,
        reservation_amount: extracted.reservation_amount || prev.reservation_amount,
        commission_pct: extracted.commission_pct || prev.commission_pct,
        expected_sign_date: extracted.expected_sign_date || prev.expected_sign_date,
        close_deadline: extracted.close_deadline || prev.close_deadline,
        earnest_money_deadline: extracted.earnest_money_deadline || prev.earnest_money_deadline,
        earnest_money_non_refundable_date: extracted.earnest_money_non_refundable_date || prev.earnest_money_non_refundable_date,
        counterpart_name: extracted.counterpart_name || prev.counterpart_name,
        counterpart_agent: extracted.counterpart_agent || prev.counterpart_agent,
        counterpart_office: extracted.counterpart_office || prev.counterpart_office,
        negotiation_details: extracted.negotiation_details || prev.negotiation_details
      }));

      alert(t('neg_ai_success'));
    } catch (err) {
      console.error(err);
      alert(err.message || t('neg_ai_error'));
    } finally {
      setAiLoading(false);
      // reset file input
      e.target.value = '';
    }
  }

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-[#0B1120] text-slate-800 dark:text-slate-200">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 pt-20 lg:pt-8">

        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
          <div>
            <h1 className="text-3xl font-bold text-slate-900 dark:text-white flex items-center gap-3">
              <span className="text-brand-500">💼</span> {t('neg_title')}
            </h1>
            <p className="text-slate-500 dark:text-slate-400 mt-1">{t('neg_subtitle')}</p>
          </div>
          <button
            onClick={() => {
              setFormData({ type: 'LOI', side: 'listing', commission_pct: 5 });
              setIsAddModalOpen(true);
            }}
            className="px-5 py-2.5 bg-brand-600 hover:bg-brand-700 text-white rounded-xl shadow-lg shadow-brand-500/20 font-medium transition-all"
          >
            {t('neg_new')}
          </button>
        </div>

        {/* ── Tab Navigation ── */}
